function printRowsForPick(){const poolMap=new Map(pickPool().map(g=>[g.poolKey,g])),currentStore=rec(),keys=[...new Set([...Object.keys(send),...Object.keys(add),...Object.keys(pull)])],out=[];keys.forEach(k=>{const parsed=parseKey(k);if(!scopeOk(parsed)||parsed.store!==currentStore)return;const g=poolMap.get(parsed.pk);if(!g)return;const s=mapVal(send,parsed.pk,currentStore),a=mapVal(add,parsed.pk,currentStore),p=mapVal(pull,parsed.pk,currentStore),qty=s+a-p;if(!qty)return;out.push({code:g.code||'',name:g.sku,qty,unit:N(g.netUnit)*1.07,inserted:g.inserted})});return out.filter(x=>T(x.name)&&N(x.qty)>0)}
